<?php require_once 'includes/config.php'; require_once 'includes/auth.php'; if (!has_permission([ROLE_ADMIN])) die('Acceso denegado.'); try { $pdo->exec('ALTER TABLE usuarios ADD COLUMN dni VARCHAR(20) DEFAULT NULL AFTER apellidos'); echo '<h1>ˇBase de datos actualizada!</h1><p>Columna DNI anadida correctamente a la tabla usuarios.</p><p>Ya puedes generar el Acta de Evaluacion Final.</p>'; } catch (PDOException $e) { if (strpos($e->getMessage(), 'Duplicate column name') !== false) { echo '<h1>ˇTodo en orden!</h1><p>La columna DNI ya existe.</p>'; } else { echo '<h1>Error al actualizar la base de datos:</h1><pre>' . htmlspecialchars($e->getMessage()) . '</pre>'; } }
